const query = $input.first().json.query ?? {};
const patientId     = query.patient_id || null;
const daysOverdue   = parseInt(query.days_overdue || '3', 10);
const autoMarkMissed = query.auto_mark_missed === 'true' || query.auto_mark_missed === true;

return [{ json: { patientId, daysOverdue, autoMarkMissed } }];

const { patientId, daysOverdue, autoMarkMissed } = $input.first().json;

const patientFilter = patientId ? `AND seq.patient_id = '${patientId}'` : '';

// Find sequences with overdue steps (earliest overdue step per sequence)
const querySQL = `
  SELECT DISTINCT ON (seq.id)
    seq.id            AS sequence_id,
    seq.patient_id,
    seq.service_name,
    ts.id             AS step_id,
    ts.step_name      AS missed_step_name,
    CURRENT_DATE - ts.scheduled_date::date AS missed_days_ago
  FROM treatment_sequences seq
  JOIN treatment_steps ts ON ts.sequence_id = seq.id
  WHERE seq.status IN ('active', 'paused')
    AND ts.status IN ('pending', 'scheduled')
    AND ts.scheduled_date IS NOT NULL
    AND ts.scheduled_date::date < CURRENT_DATE - INTERVAL '${daysOverdue} days'
    ${patientFilter}
  ORDER BY seq.id, ts.scheduled_date ASC
`;

// Auto-mark overdue steps as missed (if requested)
const markMissedSQL = autoMarkMissed ? `
  UPDATE treatment_steps
  SET status = 'missed', updated_at = NOW()
  WHERE sequence_id IN (
    SELECT id FROM treatment_sequences WHERE status IN ('active', 'paused') ${patientId ? `AND patient_id = '${patientId}'` : ''}
  )
    AND status IN ('pending', 'scheduled')
    AND scheduled_date IS NOT NULL
    AND scheduled_date::date < CURRENT_DATE - INTERVAL '${daysOverdue} days';
` : '';

return [{ json: { querySQL, markMissedSQL, patientId, daysOverdue, autoMarkMissed } }];

const rows = $input.all();
// Filter out rows that are results of UPDATE (no sequence_id), keep SELECT rows
const abandoned = rows
  .filter(r => r.json.sequence_id)
  .map(r => ({
    sequence_id: r.json.sequence_id,
    patient_id: r.json.patient_id,
    patient_name: r.json.patient_name || null,
    service_name: r.json.service_name,
    missed_step_name: r.json.missed_step_name,
    missed_days_ago: parseInt(r.json.missed_days_ago, 10) || 0,
  }));

return [{ json: { abandoned, total: abandoned.length } }];
